import { AnalyticsData, ApiResponse } from '@/types';
import { mockAnalytics, mockDoctors, mockPatients, mockAppointments } from '@/data/mockData';
import { apiSuccess } from './api';

export const analyticsService = {
  async getDashboardAnalytics(): Promise<ApiResponse<AnalyticsData>> {
    // Enrich with top doctors
    const topDoctors = [...mockDoctors]
      .sort((a, b) => b.reviewCount - a.reviewCount)
      .slice(0, 5)
      .map(doctor => ({
        doctor,
        appointmentCount: mockAppointments.filter(a => a.doctorId === doctor.id).length * 10,
      }));

    return apiSuccess({
      ...mockAnalytics,
      topDoctors,
      totalPatients: mockPatients.length * 100,
      totalDoctors: mockDoctors.length * 10,
    });
  },

  async getAppointmentStats(
    startDate: string,
    endDate: string
  ): Promise<ApiResponse<{ date: string; count: number }[]>> {
    // Generate mock daily stats
    const stats = [];
    const start = new Date(startDate);
    const end = new Date(endDate);

    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      stats.push({
        date: d.toISOString().split('T')[0],
        count: Math.floor(Math.random() * 50) + 10,
      });
    }

    return apiSuccess(stats);
  },

  async getRevenueStats(
    period: 'week' | 'month' | 'year'
  ): Promise<ApiResponse<{ label: string; revenue: number }[]>> {
    // Return appropriate data based on period
    if (period === 'year') {
      return apiSuccess(mockAnalytics.revenueByMonth.map(item => ({
        label: item.month,
        revenue: item.revenue,
      })));
    }

    // Generate weekly or monthly data
    const stats = [];
    const days = period === 'week' ? 7 : 30;

    for (let i = 0; i < days; i++) {
      stats.push({
        label: `Day ${i + 1}`,
        revenue: Math.floor(Math.random() * 30000) + 5000,
      });
    }

    return apiSuccess(stats);
  },

  async getUserGrowth(): Promise<ApiResponse<{ month: string; patients: number; doctors: number }[]>> {
    return apiSuccess(
      mockAnalytics.patientGrowth.map((item, index) => ({
        month: item.month,
        patients: item.count,
        doctors: Math.floor(item.count * 0.05) + 2,
      }))
    );
  },
};
